import{_ as a,o as t,c as s,ag as o}from"./chunks/framework._658-eYr.js";const p=JSON.parse('{"title":"Authentication & Roles","description":"","frontmatter":{},"headers":[],"relativePath":"guide/auth.md","filePath":"guide/auth.md"}'),i={name:"guide/auth.md"};function r(l,e,n,d,h,c){return t(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="authentication-roles" tabindex="-1">Authentication &amp; Roles <a class="header-anchor" href="#authentication-roles" aria-label="Permalink to &quot;Authentication &amp; Roles&quot;">​</a></h1><p>CRAFT Studio uses Keycloak for single sign-on (SSO) with role-based access control. Authentication is enforced at the infrastructure layer via Traefik ForwardAuth, so the application never handles passwords or session tokens directly.</p><h2 id="login-flow" tabindex="-1">Login Flow <a class="header-anchor" href="#login-flow" aria-label="Permalink to &quot;Login Flow&quot;">​</a></h2><ol><li><strong>User visits the studio URL</strong> (e.g., <code>https://connect.rudolphhome.com:2083/studio/</code>)</li><li><strong>Traefik ForwardAuth</strong> intercepts the request and forwards it to oauth2-proxy</li><li><strong>oauth2-proxy</strong> checks for a valid session cookie. If none exists, it redirects to <strong>Keycloak</strong></li><li><strong>Keycloak login page</strong> prompts for username and password</li><li><strong>OIDC callback</strong> — Keycloak issues an authorization code, oauth2-proxy exchanges it for tokens</li><li><strong>Session established</strong> — oauth2-proxy sets a session cookie and proxies the original request through to the studio, injecting identity headers</li></ol><p>After login, every request to the studio backend includes ForwardAuth headers that identify the user.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><p>Keycloak realm roles control what each user can see and do. Four roles are defined:</p><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><ul><li>Full access to all channels regardless of ownership</li><li>All AI models available (Opus, Sonnet, Haiku, Gemini, Ollama)</li><li>Bypasses all authorization guards</li><li>Can manage all users&#39; resources and content</li><li>Automatically qualifies as premium</li></ul><h3 id="editor" tabindex="-1">Editor <a class="header-anchor" href="#editor" aria-label="Permalink to &quot;Editor&quot;">​</a></h3><ul><li>Read access to all channels</li><li>Write access only to own channels</li><li>Standard model access (upgraded with API keys or premium role)</li></ul><h3 id="premium" tabindex="-1">Premium <a class="header-anchor" href="#premium" aria-label="Permalink to &quot;Premium&quot;">​</a></h3><ul><li>Access to advanced AI models: Claude Opus, Claude Sonnet, and all MCP tool integrations</li><li>Proposals and Jobs features unlocked (channel-scoped)</li><li>Full Claude Agent SDK capabilities</li></ul><h3 id="standard-member" tabindex="-1">Standard / Member <a class="header-anchor" href="#standard-member" aria-label="Permalink to &quot;Standard / Member&quot;">​</a></h3><ul><li>Own channels only (create, read, update, delete)</li><li>Limited to Ollama local models and Claude Haiku</li><li>No proposals or jobs access</li><li>Basic content creation features</li></ul><h2 id="_3-tier-model-access" tabindex="-1">3-Tier Model Access <a class="header-anchor" href="#_3-tier-model-access" aria-label="Permalink to &quot;3-Tier Model Access&quot;">​</a></h2><p>Model availability depends on the user&#39;s role and stored API keys:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Who qualifies</th><th>Available models</th></tr></thead><tbody><tr><td><strong>Standard</strong></td><td>All authenticated users</td><td>Ollama (local models) + Claude Haiku</td></tr><tr><td><strong>API Keys</strong></td><td>Users with stored Gemini/Claude keys</td><td>Gemini models + Haiku</td></tr><tr><td><strong>Premium</strong></td><td><code>premium</code> role or <code>admin</code> role</td><td>All Claude models (Opus, Sonnet, Haiku) + Gemini + Ollama + MCP tools</td></tr></tbody></table><p>API keys are stored per-user (encrypted AES-256-GCM in PostgreSQL) and managed via the profile avatar menu, under <strong>API Keys</strong>. The server checks user keys first, then falls back to server-wide <code>.env</code> values.</p><h2 id="password-change" tabindex="-1">Password Change <a class="header-anchor" href="#password-change" aria-label="Permalink to &quot;Password Change&quot;">​</a></h2><p>Users can change their Keycloak password without leaving the studio:</p><ol><li>Click your <strong>profile avatar</strong> in the sidebar footer</li><li>In the popover, click the <strong>Settings</strong> (gear) icon</li><li>Click the <strong>Password</strong> button</li><li>Enter your <strong>current password</strong> for verification (validated against Keycloak)</li><li>Enter and confirm your <strong>new password</strong></li><li>The new password is set via the Keycloak admin API</li></ol><p>The current password check prevents unauthorized changes if a session is left open.</p><h2 id="sign-out" tabindex="-1">Sign Out <a class="header-anchor" href="#sign-out" aria-label="Permalink to &quot;Sign Out&quot;">​</a></h2><p>Click the <strong>Sign Out</strong> button in the profile popover (sidebar footer). This redirects to <code>/</code> which clears the oauth2-proxy session and triggers the Keycloak login flow.</p><h2 id="multi-tenant-isolation" tabindex="-1">Multi-Tenant Isolation <a class="header-anchor" href="#multi-tenant-isolation" aria-label="Permalink to &quot;Multi-Tenant Isolation&quot;">​</a></h2><p>CRAFT Studio is multi-tenant by design. Every channel has a <code>user_id</code> column that ties it to the user who created it.</p><ul><li><strong>Admin</strong> — sees and manages all channels from all users</li><li><strong>Editor</strong> — reads all channels, but can only modify channels they own</li><li><strong>Standard</strong> — sees only their own channels</li></ul><p>The <code>channelAccess</code> middleware enforces these rules on every channel-scoped API request. Resources follow a similar pattern: files are owned by <code>user_id</code> with optional channel assignment via a junction table.</p><h2 id="forwardauth-headers" tabindex="-1">ForwardAuth Headers <a class="header-anchor" href="#forwardauth-headers" aria-label="Permalink to &quot;ForwardAuth Headers&quot;">​</a></h2><p>When Traefik forwards a request through oauth2-proxy, three headers are injected:</p><table tabindex="0"><thead><tr><th>Header</th><th>Contents</th></tr></thead><tbody><tr><td><code>X-Auth-Request-User</code></td><td>Keycloak username (e.g., <code>alex</code>)</td></tr><tr><td><code>X-Auth-Request-Email</code></td><td>User&#39;s email address</td></tr><tr><td><code>X-Auth-Request-Access-Token</code></td><td>JWT access token from Keycloak</td></tr></tbody></table><p>The auth middleware in <code>middleware/auth.ts</code> extracts these on every request and attaches the user identity to the request context.</p><h2 id="jwt-payload" tabindex="-1">JWT Payload <a class="header-anchor" href="#jwt-payload" aria-label="Permalink to &quot;JWT Payload&quot;">​</a></h2><p>The access token is a standard JWT. The backend decodes it to extract roles:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;realm_access&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;roles&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;admin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;premium&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;default-roles-home&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;preferred_username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alex&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alex@example.com&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The <code>realm_access.roles</code> array determines the user&#39;s permissions. Since the JWT comes from a trusted reverse proxy (Traefik + oauth2-proxy), the backend decodes it without cryptographic validation — the proxy has already verified the token with Keycloak.</p><p>Role flags derived from the JWT:</p><ul><li><code>isAdmin</code> — <code>roles</code> includes <code>admin</code></li><li><code>isEditor</code> — <code>roles</code> includes <code>editor</code></li><li><code>isPremium</code> — <code>roles</code> includes <code>premium</code> <strong>or</strong> <code>admin</code> (admin auto-qualifies)</li></ul><h2 id="dev-mode-bypass" tabindex="-1">Dev Mode Bypass <a class="header-anchor" href="#dev-mode-bypass" aria-label="Permalink to &quot;Dev Mode Bypass&quot;">​</a></h2><p>When <code>NODE_ENV</code> is not set to <code>production</code>, the auth middleware skips ForwardAuth header checks and defaults to a development user:</p><ul><li><strong>Username</strong>: <code>dev</code></li><li><strong>Roles</strong>: <code>admin</code> + <code>premium</code></li></ul><p>This allows local development without running Keycloak or oauth2-proxy. All features are unlocked in dev mode.</p>`,43)])])}const m=a(i,[["render",r]]);export{p as __pageData,m as default};
